     3→import { collection, query, orderBy, limit, onSnapshot, addDoc, serverTimestamp } from 'firebase/firestore';
     4→
     5→export function useLogs() {
     6→  const [logs, setLogs] = useState([]);
     7→
     8→  useEffect(() => {
     9→    const q = query(collection(db, "logs"), orderBy("timestamp", "desc"), limit(10));
    10→    const unsubscribe = onSnapshot(q, (snapshot) => {
    11→      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    12→      setLogs(data);
    13→    });
    14→    return () => unsubscribe();
    15→  }, []);
    16→
    17→  const addLog = async (message, type = 'info', user = null) => {
    18→    try {
    19→      await addDoc(collection(db, "logs"), {
    20→        message,
    21→        type,
    22→        user: user ? (user.isAnonymous ? 'Anonyme' : user.email) : null,
    23→        timestamp: serverTimestamp()
    24→      });
    25→    } catch (err) {
    26→      console.error("Erreur log:", err);
    27→    }
    28→  };
    29→
    30→  return { logs, addLog };
    31→}

