    25→
    26→  // No longer need to initialize functions via getFunctions(app) here
    27→  const storage = getStorage(app);
    28→
    29→  const handleSaveProduct = async (e) => {
    30→    e.preventDefault();
    31→    setIsSaving(true);
    32→    setFeedback('Sauvegarde...');
    33→
    34→    if (!productName || !weight || !expiryDate || !quantity) {
