    84→      return;
    85→    }
    86→
    87→    setIsScanning(true);
    88→    setOcrFeedback('Scan en cours...');
    89→
    90→    try {
    91→      const base64Image = (imageData || capturedExpiryImage).split(',')[1]; // Use imageData if provided, else from state
    92→      const expectedFunctionUrl = `https://us-central1-dashboard-mictlan-dev.cloudfunctions.net/extractExpiryDateFromImage`;
    93→
    94→      const requestBody = {
    95→          data: base64Image
    96→      };
    97→
    98→      const response = await fetch(expectedFunctionUrl, {
    99→        method: 'POST',
   100→        headers: {
   101→          'Content-Type': 'application/json',
   102→        },
   103→        body: JSON.stringify(requestBody),
   104→      });
   105→
   106→      if (!response.ok) {
   107→        const errorText = await response.text();
   108→        throw new Error(`HTTP error! status: ${response.status}, body: ${errorText}`);
   109→      }
   110→
   111→      const responseData = await response.json();
   112→      const result = responseData.result || responseData; // Handle SDK-like wrapper and direct response
   113→
   114→      if (result && result.expiryDate) {
   115→        setExpiryDate(result.expiryDate);
   116→        setOcrFeedback('Date détectée avec succès !');
   117→      } else if (result && result.message) {
   118→        setOcrFeedback(result.message);
   119→      } else if (responseData.error) {
   120→        setOcrFeedback(`Erreur: ${responseData.error.message}`);
   121→      } else {
   122→        setOcrFeedback(`Erreur inattendue: ${JSON.stringify(responseData)}`);
   123→      }
   124→
   125→    } catch (error) {
   126→      console.error("Error during OCR scan:", error);
   127→      setOcrFeedback(`Erreur lors du scan: ${error.message}`);
   128→    } finally {
   129→      setIsScanning(false);
   130→      setTimeout(() => setOcrFeedback(''), 3000);
   131→    }
   132→  };
