   164→            <label htmlFor="unit" className="block text-gray-400 mb-1">Unité</label>
   165→            <select
   166→              id="unit"
   167→              value={unit}
   168→              onChange={(e) => setUnit(e.target.value)}
   169→              className="w-full p-2 bg-black/40 text-white border border-gray-700 rounded focus:outline-none focus:ring-1 focus:ring-mictlan-gold"
   170→            >
   171→              <option value="g">grammes (g)</option>
   172→              <option value="ml">millilitres (ml)</option>
   173→              <option value="unit">unité(s)</option>
   174→            </select>
   175→          </div>
   176→        </div>
   177→
   178→        <div>
