     9→export default function ProductList() {
    10→  const [products, setProducts] = useState([]);
    11→  const [loading, setLoading] = useState(true);
    12→  const [error, setError] = useState(null);
    13→  const [editingProductId, setEditingProductId] = useState(null); // State to manage editing
    14→
    15→  // Initialize Firebase Storage
    16→  const storage = getStorage();
    17→
    18→  useEffect(() => {
    19→    const q = query(collection(db, 'products'), orderBy('expiryDate', 'asc'));
    20→
    21→    const unsubscribe = onSnapshot(q, (snapshot) => {
    22→      const fetchedProducts = snapshot.docs.map(doc => {
    23→        const data = doc.data();
    24→        const expiryDate = data.expiryDate?.toDate();
    25→        const creationDate = data.creationDate?.toDate();
    26→        return {
    27→          id: doc.id,
    28→          ...data,
    29→          expiryDate: expiryDate ? expiryDate.toLocaleDateString('fr-FR') : 'N/A',
    30→          creationDate: creationDate ? creationDate.toLocaleDateString('fr-FR') : 'N/A',
    31→        };
    32→      });
    33→      setProducts(fetchedProducts);
    34→      setLoading(false);
    35→    }, (err) => {
    36→      console.error("Error fetching products:", err);
    37→      setError("Erreur lors du chargement des produits.");
    38→      setLoading(false);
    39→    });
    40→
    41→    return () => unsubscribe(); // Cleanup the listener
    42→  }, []);
    43→
    44→  const handleDeleteProduct = async (productId) => {
    45→    if (window.confirm("Êtes-vous sûr de vouloir supprimer ce produit ?")) {
    46→      try {
    47→        await deleteDoc(doc(db, 'products', productId));
    48→        alert("Produit supprimé avec succès !");
    49→      } catch (error) {
    50→        console.error("Error deleting product:", error);
    51→        alert("Erreur lors de la suppression du produit.");
    52→      }
    53→    }
    54→  };
    55→
    56→  const handleEditClick = (productId) => {
    57→    setEditingProductId(productId);
    58→  };
    59→
    60→  const handleCloseEditForm = () => {
    61→    setEditingProductId(null);
    62→  };
    63→
    64→  if (loading) {
