    94→                      className="text-gray-400 hover:text-mictlan-gold transition-colors"
    95→                    >
    96→                      <Edit size={16} />
    97→                    </button>
    98→                    <button 
    99→                      onClick={() => handleDeleteProduct(product.id)}
   100→                      className="text-gray-400 hover:text-red-500 transition-colors"
   101→                    >
   102→                      <Trash2 size={16} />
   103→                    </button>
   104→                  </div>
   105→                </div>
   106→                <span className={`px-2 py-1 rounded-full text-xs font-semibold ${
   107→                    product.decisionStatus === 'to_handle' ? 'bg-red-500/20 text-red-400' :
   108→                    product.decisionStatus === 'promoted' ? 'bg-green-500/20 text-green-400' :
   109→                    'bg-gray-500/20 text-gray-400'
   110→                  }`}
   111→                >
   112→                  {product.decisionStatus.replace('_', ' ')}
   113→                </span>
   114→                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 text-gray-300 text-xs mt-2">
   115→                  <p className="flex items-center"><CalendarDays size={12} className="mr-1 text-gray-500" /> Péremption: {product.expiryDate}</p>
   116→                  <p className="flex items-center"><Scale size={12} className="mr-1 text-gray-500" /> Poids: {product.weight} {product.unit}</p>
   117→                  <p className="flex items-center"><Package size={12} className="mr-1 text-gray-500" /> Quantité: {product.quantity}</p>
   118→                  {product.category && <p className="flex items-center"><Tag size={12} className="mr-1 text-gray-500" /> Catégorie: {product.category}</p>}
   119→                  {product.price && <p className="flex items-center"><ListFilter size={12} className="mr-1 text-gray-500" /> Prix: {product.price}€</p>}
   120→                  {product.photos && product.photos.length > 0 && (
   121→                    <div className="sm:col-span-2 w-full"> {/* Added w-full here */}
   122→                      <img src={product.photos[0]} alt={product.name} className="mt-2 max-h-24 object-contain rounded" />
   123→                    </div>
   124→                  )}
   125→                </div>
   126→              </li>
   127→            ))}
   128→          </ul>
   129→        )}
   130→      </Card>
   131→
   132→      {editingProductId && (
   133→        <div className="fixed inset-0 bg-black bg-opacity-75 flex items-center justify-center z-50">
   134→          <div className="relative bg-gray-900 p-6 rounded-lg max-h-[90vh] overflow-y-auto w-full max-w-md">
   135→            <button 
   136→              onClick={handleCloseEditForm}
   137→              className="absolute top-3 right-3 text-gray-400 hover:text-white"
   138→            >
   139→              &times;
   140→            </button>
   141→            <ProductEditForm productId={editingProductId} onClose={handleCloseEditForm} />
   142→          </div>
   143→        </div>
   144→      )}
   145→    </>
   146→  );
   147→}
